import { describe, expect, it, beforeEach, afterEach, vi } from 'vitest';
import {
  installGgTimerBootstrap,
  isGgTimerBootstrapActive,
  ggTimerRegistrySize,
  nativeSetTimeout,
  type GgTimerRelay,
} from './gg-timers';

// ─── Mock Relay ─────────────────────────────────────────────────────

function createMockRelay(): GgTimerRelay & {
  lastEnvelope: string | null;
  envelopes: string[];
  triggerMessage: (text: string) => void;
  simulateDelivery: (envelope: string) => void;
} {
  let messageHandler: ((text: string) => void) | null = null;
  const envelopes: string[] = [];

  const relay = {
    send(text: string): void {
      envelopes.push(text);
      (relay as unknown as { lastEnvelope: string | null }).lastEnvelope = text;
    },
    onMessage(handler: (text: string) => void): () => void {
      messageHandler = handler;
      return () => {
        if (messageHandler === handler) messageHandler = null;
      };
    },
    lastEnvelope: null as string | null,
    envelopes,
    triggerMessage(text: string): void {
      messageHandler?.(text);
    },
    /**
     * Parse the last sent prism envelope and trigger its payload back as
     * an incoming message. Simulates the relay holding the message and
     * delivering it after the delay.
     */
    simulateDelivery(envelope: string): void {
      try {
        const parsed = JSON.parse(envelope) as { payload?: string };
        if (parsed.payload && messageHandler) {
          messageHandler(parsed.payload);
        }
      } catch {
        // ignore
      }
    },
  };

  return relay;
}

// ─── Setup / Teardown ───────────────────────────────────────────────

let uninstall: (() => void) | null = null;

afterEach(() => {
  if (uninstall) {
    uninstall();
    uninstall = null;
  }
});

// ─── Tests ──────────────────────────────────────────────────────────

describe('gg-timers: native passthroughs', () => {
  it('nativeSetTimeout is available', () => {
    expect(typeof nativeSetTimeout).toBe('function');
  });

  it('nativeSetTimeout fires after delay', async () => {
    let fired = false;
    nativeSetTimeout(() => {
      fired = true;
    }, 10);
    await new Promise((r) => nativeSetTimeout(r, 30));
    expect(fired).toBe(true);
  });
});

describe('gg-timers: bootstrap lifecycle', () => {
  it('install returns uninstall function', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    expect(typeof uninstall).toBe('function');
    expect(isGgTimerBootstrapActive()).toBe(true);
    uninstall();
    uninstall = null;
    expect(isGgTimerBootstrapActive()).toBe(false);
  });

  it('uninstall restores native globals', () => {
    const relay = createMockRelay();
    const originalSetTimeout = globalThis.setTimeout;
    uninstall = installGgTimerBootstrap(relay);
    expect(globalThis.setTimeout).not.toBe(originalSetTimeout);
    uninstall();
    uninstall = null;
    expect(globalThis.setTimeout).toBe(originalSetTimeout);
  });

  it('second install uninstalls the first', () => {
    const relay1 = createMockRelay();
    const relay2 = createMockRelay();
    const un1 = installGgTimerBootstrap(relay1);
    uninstall = installGgTimerBootstrap(relay2);
    expect(isGgTimerBootstrapActive()).toBe(true);
    // un1 is stale but calling it shouldn't explode
    expect(() => un1()).not.toThrow();
  });
});

describe('gg-timers: setTimeout routing', () => {
  it('sub-50ms delay falls through to native (no prism)', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    let fired = false;
    globalThis.setTimeout(() => {
      fired = true;
    }, 10);
    // No prism envelope sent
    expect(relay.envelopes.length).toBe(0);
    expect(fired).toBe(false); // hasn't fired yet, but native is scheduled
  });

  it('>=50ms delay sends a prism envelope', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    globalThis.setTimeout(() => {
      /* noop */
    }, 5000);
    expect(relay.envelopes.length).toBe(1);
    const envelope = JSON.parse(relay.envelopes[0]) as {
      type: string;
      delayMs: number;
    };
    expect(envelope.type).toBe('prism');
    expect(envelope.delayMs).toBe(5000);
  });

  it('handler fires when prism payload arrives', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    let fireCount = 0;
    globalThis.setTimeout(() => {
      fireCount++;
    }, 1000);
    relay.simulateDelivery(relay.envelopes[0]);
    expect(fireCount).toBe(1);
  });

  it('timeout handler removes itself after firing', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    globalThis.setTimeout(() => {
      /* noop */
    }, 1000);
    expect(ggTimerRegistrySize()).toBe(1);
    relay.simulateDelivery(relay.envelopes[0]);
    expect(ggTimerRegistrySize()).toBe(0);
  });

  it('passes extra args to the handler', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    let received: unknown[] = [];
    globalThis.setTimeout((a, b, c) => {
      received = [a, b, c];
    }, 500, 'x', 42, true);
    relay.simulateDelivery(relay.envelopes[0]);
    expect(received).toEqual(['x', 42, true]);
  });
});

describe('gg-timers: setInterval routing', () => {
  it('interval re-schedules itself after firing', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    globalThis.setInterval(() => {
      /* noop */
    }, 2000);
    expect(relay.envelopes.length).toBe(1);
    // Deliver the first fire -- should schedule another envelope
    relay.simulateDelivery(relay.envelopes[0]);
    expect(relay.envelopes.length).toBe(2);
    // Registry stays populated for interval
    expect(ggTimerRegistrySize()).toBe(1);
  });

  it('interval fires multiple times', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    let fireCount = 0;
    globalThis.setInterval(() => {
      fireCount++;
    }, 500);
    relay.simulateDelivery(relay.envelopes[0]);
    relay.simulateDelivery(relay.envelopes[1]);
    relay.simulateDelivery(relay.envelopes[2]);
    expect(fireCount).toBe(3);
  });
});

describe('gg-timers: clearTimeout / clearInterval', () => {
  it('clearTimeout prevents handler from firing', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    let fired = false;
    const id = globalThis.setTimeout(() => {
      fired = true;
    }, 1000);
    globalThis.clearTimeout(id);
    relay.simulateDelivery(relay.envelopes[0]);
    expect(fired).toBe(false);
    expect(ggTimerRegistrySize()).toBe(0);
  });

  it('clearInterval stops re-scheduling', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    const id = globalThis.setInterval(() => {
      /* noop */
    }, 500);
    expect(relay.envelopes.length).toBe(1);
    globalThis.clearInterval(id);
    relay.simulateDelivery(relay.envelopes[0]);
    // No new envelope after cancel
    expect(relay.envelopes.length).toBe(1);
    expect(ggTimerRegistrySize()).toBe(0);
  });

  it('clearing an unknown numeric id does not throw', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    expect(() => globalThis.clearTimeout(999999 as unknown as ReturnType<typeof setTimeout>)).not.toThrow();
  });
});

describe('gg-timers: persistence semantics', () => {
  it('envelope contains the handler id for replay', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    globalThis.setTimeout(() => {
      /* noop */
    }, 1000);
    const envelope = JSON.parse(relay.envelopes[0]) as { payload: string };
    const payload = JSON.parse(envelope.payload) as { tag: string; id: string };
    expect(payload.tag).toBe('__gg-timer-fire__');
    expect(typeof payload.id).toBe('string');
    expect(payload.id.startsWith('gg-')).toBe(true);
  });

  it('multiple concurrent timers have distinct ids', () => {
    const relay = createMockRelay();
    uninstall = installGgTimerBootstrap(relay);
    const ids = new Set<string>();
    for (let i = 0; i < 10; i++) {
      globalThis.setTimeout(() => {
        /* noop */
      }, 1000);
    }
    for (const env of relay.envelopes) {
      const payload = JSON.parse(JSON.parse(env).payload) as { id: string };
      ids.add(payload.id);
    }
    expect(ids.size).toBe(10);
  });
});
